head.b:skin:
/*
Theme Name: Ayman IT Service
Theme Author: Ayman IT Service
Description: Premium Blogger theme for digital service business
*/

/* Variable definitions
====================
<Variable name="primary" description="Primary Color" type="color" default="#2563eb" value="#2563eb"/>
<Variable name="accent" description="Accent Color" type="color" default="#06b6d4" value="#06b6d4"/>
<Variable name="bg" description="Background" type="color" default="#ffffff" value="#ffffff"/>
<Variable name="text" description="Text" type="color" default="#0f172a" value="#0f172a"/>
<Variable name="muted" description="Muted" type="color" default="#64748b" value="#64748b"/>
<Variable name="card" description="Card BG" type="color" default="#f8fafc" value="#f8fafc"/>
<Variable name="whatsapp" description="WhatsApp" type="color" default="#25d366" value="#25d366"/>
<Variable name="body.font" description="Body Font" type="font" default="normal normal 15px Inter, sans-serif" value="normal normal 15px Inter, sans-serif"/>
*/

*{margin:0;padding:0;box-sizing:border-box}
body{font-family:'Inter','Hind Siliguri',sans-serif;color:$(text);background:$(bg);line-height:1.6;font-size:15px}
a{color:inherit;text-decoration:none}
img{max-width:100%;height:auto;display:block}
.container{max-width:1200px;margin:0 auto;padding:0 20px}
h1,h2,h3,h4{font-weight:700;letter-spacing:-.02em;line-height:1.2}
.btn{display:inline-flex;align-items:center;gap:8px;padding:12px 24px;border-radius:10px;font-weight:600;font-size:14px;cursor:pointer;border:0;transition:all .25s}
.btn-primary{background:linear-gradient(135deg,$(primary),$(accent));color:#fff;box-shadow:0 10px 25px -10px $(primary)}
.btn-primary:hover{transform:translateY(-2px);opacity:.95}
.btn-outline{background:transparent;border:1px solid #e2e8f0;color:$(text)}
.btn-outline:hover{background:$(card)}

/* HEADER */
.site-header{position:fixed;top:0;left:0;right:0;z-index:100;background:rgba(255,255,255,.85);backdrop-filter:blur(12px);border-bottom:1px solid #e2e8f0;transition:all .3s}
.header-inner{display:flex;align-items:center;justify-content:space-between;height:72px}
.logo{display:flex;align-items:center;gap:10px;font-weight:800;font-size:18px}
.logo-icon{width:42px;height:42px;border-radius:12px;background:linear-gradient(135deg,$(primary),$(accent));display:flex;align-items:center;justify-content:center;color:#fff;font-weight:800;box-shadow:0 8px 20px -6px $(primary)}
.logo-text small{display:block;font-size:10px;color:$(muted);letter-spacing:.15em;font-weight:500;text-transform:uppercase}
.main-nav{display:flex;gap:28px}
.main-nav a{font-size:14px;font-weight:500;color:$(text);transition:color .2s}
.main-nav a:hover{color:$(primary)}
.header-cta{display:flex;gap:8px;align-items:center}
.menu-toggle{display:none;background:transparent;border:0;font-size:22px;cursor:pointer;color:$(text)}
@media (max-width:900px){
  .main-nav{display:none;position:absolute;top:72px;left:0;right:0;background:#fff;flex-direction:column;padding:20px;border-bottom:1px solid #e2e8f0;gap:0}
  .main-nav.open{display:flex}
  .main-nav a{padding:12px 0;border-bottom:1px solid #f1f5f9}
  .menu-toggle{display:block}
  .header-cta .btn:not(.menu-toggle){display:none}
}

/* HERO */
.hero{position:relative;margin-top:72px;height:88vh;min-height:560px;max-height:780px;overflow:hidden}
.hero-slide{position:absolute;inset:0;opacity:0;transition:opacity 1s}
.hero-slide.active{opacity:1}
.hero-slide img{width:100%;height:100%;object-fit:cover}
.hero-overlay{position:absolute;inset:0;background:linear-gradient(135deg,rgba(30,58,138,.85),rgba(14,116,144,.75))}
.hero-content{position:relative;z-index:2;height:100%;display:flex;align-items:center;color:#fff}
.hero-badge{display:inline-flex;align-items:center;gap:8px;padding:8px 16px;background:rgba(255,255,255,.15);backdrop-filter:blur(8px);border:1px solid rgba(255,255,255,.2);border-radius:99px;font-size:12px;font-weight:500;margin-bottom:20px}
.hero-badge .dot{width:8px;height:8px;border-radius:50%;background:$(whatsapp);box-shadow:0 0 12px $(whatsapp)}
.hero h1{font-size:clamp(36px,5vw,68px);margin-bottom:16px;max-width:700px}
.hero p{font-size:clamp(15px,1.5vw,20px);max-width:600px;margin-bottom:32px;opacity:.95}
.hero-actions{display:flex;gap:12px;flex-wrap:wrap}
.hero-actions .btn-light{background:#fff;color:$(primary)}
.hero-dots{position:absolute;bottom:24px;left:50%;transform:translateX(-50%);display:flex;gap:8px;z-index:3}
.hero-dots button{width:8px;height:8px;border-radius:99px;background:rgba(255,255,255,.5);border:0;cursor:pointer;transition:all .3s}
.hero-dots button.active{width:32px;background:#fff}
.hero-arrow{position:absolute;top:50%;transform:translateY(-50%);z-index:3;width:44px;height:44px;border-radius:50%;background:rgba(255,255,255,.15);backdrop-filter:blur(8px);border:1px solid rgba(255,255,255,.3);color:#fff;cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:18px}
.hero-arrow.prev{left:20px}.hero-arrow.next{right:20px}

/* SECTION */
section{padding:80px 0}
.section-head{text-align:center;max-width:600px;margin:0 auto 50px}
.section-kicker{font-size:13px;font-weight:600;color:$(primary);text-transform:uppercase;letter-spacing:.15em;margin-bottom:12px}
.section-title{font-size:clamp(28px,3.5vw,44px);margin-bottom:14px}
.section-desc{color:$(muted)}

/* SERVICES */
.services-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:20px}
.service-card{padding:24px;background:#fff;border:1px solid #e2e8f0;border-radius:18px;transition:all .3s}
.service-card:hover{transform:translateY(-4px);box-shadow:0 20px 40px -20px rgba(37,99,235,.25);border-color:transparent}
.service-icon{width:52px;height:52px;border-radius:12px;background:linear-gradient(135deg,$(primary),$(accent));display:flex;align-items:center;justify-content:center;color:#fff;font-size:22px;margin-bottom:16px}
.service-card h3{font-size:18px;margin-bottom:8px}
.service-card p{color:$(muted);font-size:14px;margin-bottom:14px}
.service-card a{color:$(primary);font-weight:600;font-size:14px}

/* ABOUT */
.about{background:$(card)}
.about-grid{display:grid;grid-template-columns:1fr 1fr;gap:50px;align-items:center}
.about-img{border-radius:20px;box-shadow:0 30px 60px -20px rgba(15,23,42,.25);position:relative}
.about-badge{position:absolute;bottom:-24px;right:-24px;background:#fff;padding:18px 22px;border-radius:16px;box-shadow:0 20px 40px -10px rgba(15,23,42,.2);display:flex;gap:12px;align-items:center}
.about-badge .num{font-size:26px;font-weight:800;color:$(primary)}
.feature-grid{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin:22px 0}
.feature-grid div{display:flex;gap:8px;align-items:center;padding:12px;background:#fff;border:1px solid #e2e8f0;border-radius:10px;font-size:14px;font-weight:500}
.feature-grid i{color:$(whatsapp)}
@media (max-width:800px){.about-grid{grid-template-columns:1fr}}

/* STATS */
.stats{background:linear-gradient(135deg,$(primary),$(accent));color:#fff;padding:60px 0}
.stats-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:30px;text-align:center}
.stats-grid .num{font-size:clamp(28px,4vw,48px);font-weight:800;margin-bottom:6px}
.stats-grid .lbl{font-size:14px;opacity:.9}
@media (max-width:600px){.stats-grid{grid-template-columns:1fr 1fr}}

/* GALLERY */
.gallery-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:16px}
.gallery-item{aspect-ratio:4/3;overflow:hidden;border-radius:16px;position:relative;cursor:pointer}
.gallery-item img{width:100%;height:100%;object-fit:cover;transition:transform .6s}
.gallery-item:hover img{transform:scale(1.1)}

/* VIDEO */
.video-wrap{max-width:900px;margin:0 auto;aspect-ratio:16/9;border-radius:20px;overflow:hidden;box-shadow:0 30px 60px -20px rgba(15,23,42,.3)}
.video-wrap iframe{width:100%;height:100%;border:0}

/* TESTIMONIALS */
.testimonials{background:$(card)}
.testimonial{max-width:720px;margin:0 auto;background:#fff;padding:50px 40px;border-radius:24px;text-align:center;box-shadow:0 20px 50px -20px rgba(15,23,42,.15)}
.testimonial .stars{color:#fbbf24;margin-bottom:14px;font-size:18px}
.testimonial blockquote{font-size:18px;font-style:italic;margin-bottom:18px}
.testimonial .name{font-weight:700}
.testimonial .role{font-size:13px;color:$(muted)}
.t-nav{display:flex;justify-content:center;gap:8px;margin-top:24px}
.t-nav button{width:8px;height:8px;border-radius:99px;border:0;background:#e2e8f0;cursor:pointer;transition:all .3s}
.t-nav button.active{width:28px;background:$(primary)}

/* BLOG */
.blog-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));gap:24px}
.blog-card{background:#fff;border:1px solid #e2e8f0;border-radius:18px;overflow:hidden;transition:all .3s}
.blog-card:hover{transform:translateY(-4px);box-shadow:0 20px 40px -20px rgba(15,23,42,.2)}
.blog-card .thumb{aspect-ratio:16/10;overflow:hidden}
.blog-card .thumb img{width:100%;height:100%;object-fit:cover;transition:transform .6s}
.blog-card:hover .thumb img{transform:scale(1.1)}
.blog-card .body{padding:20px}
.blog-card .date{font-size:12px;color:$(muted);margin-bottom:6px}
.blog-card h3{font-size:18px;margin-bottom:10px}
.blog-card h3 a:hover{color:$(primary)}
.read-more{color:$(primary);font-weight:600;font-size:14px}

/* CONTACT */
.contact-grid{display:grid;grid-template-columns:1fr 1fr;gap:40px}
@media (max-width:800px){.contact-grid{grid-template-columns:1fr}}
.contact-form{background:$(card);padding:30px;border-radius:20px;border:1px solid #e2e8f0}
.contact-form .row{display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:14px}
.contact-form input,.contact-form textarea{width:100%;padding:12px 14px;border:1px solid #e2e8f0;border-radius:10px;background:#fff;font:inherit;outline:none;transition:border .2s}
.contact-form input:focus,.contact-form textarea:focus{border-color:$(primary)}
.contact-form textarea{resize:vertical;min-height:120px;margin-bottom:14px}
.contact-info{display:flex;flex-direction:column;gap:14px}
.info-item{display:flex;gap:14px;align-items:center;padding:16px;background:#fff;border:1px solid #e2e8f0;border-radius:14px;transition:all .3s}
.info-item:hover{box-shadow:0 10px 30px -10px rgba(37,99,235,.2)}
.info-item .ic{width:46px;height:46px;border-radius:12px;background:linear-gradient(135deg,$(primary),$(accent));color:#fff;display:flex;align-items:center;justify-content:center;font-size:18px}
.info-item small{display:block;font-size:12px;color:$(muted)}
.info-item strong{font-weight:600}
.map{aspect-ratio:16/10;border-radius:14px;overflow:hidden;border:1px solid #e2e8f0}
.map iframe{width:100%;height:100%;border:0}

/* FOOTER */
footer{background:$(text);color:#fff;padding:60px 0 24px}
.footer-grid{display:grid;grid-template-columns:1.4fr 1fr 1fr 1.2fr;gap:36px;margin-bottom:36px}
@media (max-width:800px){.footer-grid{grid-template-columns:1fr 1fr}}
@media (max-width:500px){.footer-grid{grid-template-columns:1fr}}
footer h4{margin-bottom:16px;font-size:15px}
footer ul{list-style:none}
footer ul li{margin-bottom:10px;font-size:14px;opacity:.8}
footer ul li a:hover{color:$(accent);opacity:1}
.social-icons{display:flex;gap:8px;margin-top:14px}
.social-icons a{width:36px;height:36px;border-radius:10px;background:rgba(255,255,255,.1);display:flex;align-items:center;justify-content:center;transition:all .3s}
.social-icons a:hover{background:$(primary)}
.footer-bottom{border-top:1px solid rgba(255,255,255,.1);padding-top:20px;text-align:center;font-size:13px;opacity:.7}

/* FLOATING BUTTONS */
.float-wa,.float-call,.back-top{position:fixed;width:54px;height:54px;border-radius:50%;display:flex;align-items:center;justify-content:center;color:#fff;font-size:22px;z-index:99;box-shadow:0 12px 28px -8px rgba(0,0,0,.3);transition:transform .25s;cursor:pointer;border:0}
.float-wa{bottom:24px;right:24px;background:$(whatsapp);animation:pulse 2s infinite}
.float-call{bottom:90px;right:24px;background:linear-gradient(135deg,$(primary),$(accent))}
.back-top{bottom:24px;left:24px;background:#fff;color:$(text);border:1px solid #e2e8f0;display:none}
.back-top.show{display:flex}
.float-wa:hover,.float-call:hover,.back-top:hover{transform:scale(1.1)}
@keyframes pulse{0%,100%{box-shadow:0 0 0 0 rgba(37,211,102,.6)}50%{box-shadow:0 0 0 16px rgba(37,211,102,0)}}

/* WIDGETS (sidebar) */
.widget{background:#fff;border:1px solid #e2e8f0;border-radius:14px;padding:20px;margin-bottom:20px}
.widget h2{font-size:16px;margin-bottom:14px;padding-bottom:10px;border-bottom:2px solid $(primary);display:inline-block}

/* DARK MODE */
body.dark-mode{background:#0f172a;color:#f1f5f9}
body.dark-mode .site-header{background:rgba(15,23,42,.85);border-color:#1e293b}
body.dark-mode .service-card,body.dark-mode .blog-card,body.dark-mode .info-item,body.dark-mode .testimonial,body.dark-mode .widget,body.dark-mode .feature-grid div{background:#1e293b;border-color:#334155;color:#f1f5f9}
body.dark-mode .about,body.dark-mode .testimonials{background:#0a1120}
body.dark-mode .contact-form{background:#1e293b;border-color:#334155}
body.dark-mode .contact-form input,body.dark-mode .contact-form textarea{background:#0f172a;border-color:#334155;color:#f1f5f9}
body.dark-mode .logo-text{color:#f1f5f9}
body.dark-mode .main-nav a{color:#f1f5f9}

body.script:
//
  // Hero slider
  var curSlide = 0;
  var slides = document.querySelectorAll('.hero-slide');
  var dots = document.querySelectorAll('#heroDots button');
  function goSlide(i){
    slides[curSlide].classList.remove('active');
    dots[curSlide].classList.remove('active');
    curSlide = (i + slides.length) % slides.length;
    slides[curSlide].classList.add('active');
    dots[curSlide].classList.add('active');
  }
  function heroSlide(dir){ goSlide(curSlide + dir); }
  setInterval(function(){ goSlide(curSlide + 1); }, 5000);

  // Testimonials
  var tData = [
    {q:'"অসাধারণ সার্ভিস। দ্রুত এবং নির্ভরযোগ্য। আমার সব অনলাইন কাজ এখানেই করাই।"', n:'Rahim Uddin', r:'Customer'},
    {q:'"Photo studio এর কাজ খুব সুন্দর হয়েছে। স্টাফরা অনেক হেল্পফুল।"', n:'Fatema Begum', r:'Customer'},
    {q:'"Best mobile accessories shop in town. Genuine products and great pricing."', n:'Sajid Hasan', r:'Tech Buyer'}
  ];
  var curT = 0;
  function goTest(i){
    curT = i;
    document.getElementById('tQuote').textContent = tData[i].q;
    document.getElementById('tName').textContent = tData[i].n;
    document.getElementById('tRole').textContent = tData[i].r;
    document.querySelectorAll('#tNav button').forEach(function(b,k){ b.classList.toggle('active', k===i); });
  }
  setInterval(function(){ goTest((curT + 1) % tData.length); }, 6000);

  // Back to top
  window.addEventListener('scroll', function(){
    document.getElementById('backTop').classList.toggle('show', window.scrollY > 400);
  });

  // Dark mode (with persistence)
  function toggleDark(){
    document.body.classList.toggle('dark-mode');
    localStorage.setItem('ayman-dark', document.body.classList.contains('dark-mode') ? '1' : '0');
  }
  if(localStorage.getItem('ayman-dark') === '1'){ document.body.classList.add('dark-mode'); }

  // Contact form (mailto fallback)
  function sendMsg(e){
    e.preventDefault();
    var f = e.target;
    var body = 'Name: ' + f.name.value + '%0AMobile: ' + f.mobile.value + '%0AEmail: ' + f.email.value + '%0A%0A' + encodeURIComponent(f.message.value);
    window.location.href = 'mailto:info@aymanit.com?subject=' + encodeURIComponent(f.subject.value) + '&body=' + body;
  }

  // Animated counter
  function animateCount(el){
    var target = parseInt(el.dataset.count, 10);
    var dur = 1500, start = performance.now();
    function tick(t){
      var p = Math.min((t - start)/dur, 1);
      el.textContent = Math.floor(p*target).toLocaleString() + '+';
      if(p<1) requestAnimationFrame(tick);
    }
    requestAnimationFrame(tick);
  }
  var observed = new Set();
  var io = new IntersectionObserver(function(entries){
    entries.forEach(function(en){
      if(en.isIntersecting && !observed.has(en.target)){
        observed.add(en.target); animateCount(en.target);
      }
    });
  });
  document.querySelectorAll('[data-count]').forEach(function(el){ io.observe(el); });
//
